package main

import (
    "sync"
)

type Bank struct {
    accounts map[string]float64
    mutex    sync.RWMutex
}

func NewBank() *Bank {
    return &Bank{
        accounts: make(map[string]float64),
    }
}

func (b *Bank) GetBalance(accountID string) float64 {
    b.mutex.RLock()
    defer b.mutex.RUnlock()
    return b.accounts[accountID]
}

func (b *Bank) Deposit(accountID string, amount float64) error {
    if amount <= 0 {
        return fmt.Errorf("deposit amount must be positive")
    }
    
    b.mutex.Lock()
    defer b.mutex.Unlock()
    b.accounts[accountID] += amount
    return nil
}

func (b *Bank) Withdraw(accountID string, amount float64) error {
    if amount <= 0 {
        return fmt.Errorf("withdrawal amount must be positive")
    }
    
    b.mutex.Lock()
    defer b.mutex.Unlock()
    
    balance := b.accounts[accountID]
    if balance < amount {
        return fmt.Errorf("insufficient funds")
    }
    
    b.accounts[accountID] -= amount
    return nil
}

func (b *Bank) Transfer(fromAccount, toAccount string, amount float64) error {
    if amount <= 0 {
        return fmt.Errorf("transfer amount must be positive")
    }
    
    if fromAccount == toAccount {
        return nil
    }
    
    b.mutex.Lock()
    
    balance := b.accounts[fromAccount]
    if balance < amount {
        b.mutex.Unlock()
        return fmt.Errorf("insufficient funds")
    }
    
    b.accounts[fromAccount] -= amount
    b.accounts[toAccount] += amount
    
    b.mutex.Unlock()
    return nil
}

func (b *Bank) CreateAccount(accountID string, initialBalance float64) error {
    if initialBalance < 0 {
        return fmt.Errorf("initial balance cannot be negative")
    }
    
    b.mutex.Lock()
    defer b.mutex.Unlock()
    
    if _, exists := b.accounts[accountID]; exists {
        return fmt.Errorf("account already exists")
    }
    
    b.accounts[accountID] = initialBalance
    return nil
}